import { type ReactNode } from 'react';
import { FormattedMessage } from 'react-intl';

import { _EmptyState as EmptyState } from '@dynatrace/strato-components/charts';

interface BaseLayerDataErrorProps {
  height: number | string;
}

export const BaseLayerDataError = ({ height }: BaseLayerDataErrorProps) => {
  const messageNode: ReactNode = (
    <FormattedMessage
      id="tS7epcIvtrbIhuBy"
      defaultMessage="An error occurred: Failed to load map data."
      description="Message to display when an error occurred while getting map data."
    />
  );

  return <EmptyState height={height}>{messageNode}</EmptyState>;
};

BaseLayerDataError.displayName = 'BaseLayerDataError';
